# ─────────────────────────────────────────────
# ConsecutiveFailureTracker — generalized circuit breaker
# Inspired by Claude Code autoCompact.ts MAX_CONSECUTIVE_AUTOCOMPACT_FAILURES
# ─────────────────────────────────────────────
class ConsecutiveFailureTracker:
    """Generic circuit breaker for repeated failures of the same kind.

    Usage:
        tracker = ConsecutiveFailureTracker(max_consecutive=3)
        if tracker.note("empty_output"):  # returns True if tripped
            handle_circuit_break()
        tracker.reset()                    # on success
    """
    __slots__ = ("_max", "_count", "_kind")

    def __init__(self, max_consecutive: int = 3):
        self._max = max(1, max_consecutive)
        self._count = 0
        self._kind = ""

    def note(self, kind: str = "generic") -> bool:
        """Record a failure of *kind* and return True if the breaker trips."""
        kind = str(kind or "generic").strip()
        if kind == self._kind:
            self._count += 1
        else:
            self._kind = kind
            self._count = 1
        return self._count >= self._max

    def reset(self) -> None:
        self._count = 0
        self._kind = ""

    @property
    def count(self) -> int:
        return self._count

    @property
    def kind(self) -> str:
        return self._kind

    @property
    def tripped(self) -> bool:
        return self._count >= self._max


# ─────────────────────────────────────────
# Continue / keep-going input detection
# Inspired by Claude Code userPromptKeywords.ts
# ─────────────────────────────────────────
_CONTINUATION_INPUT_RE = re.compile(
    r"^(?:continue|继续|keep going|go on|接着|接着做|继续做|接着搞|往下做)$",
    re.IGNORECASE,
)

def is_continuation_input(text: str) -> bool:
    """Detect bare continuation prompts that should skip re-planning."""
    return bool(_CONTINUATION_INPUT_RE.match(str(text or "").strip()))


# ─────────────────────────────────────────
# User frustration detection
# Inspired by Claude Code userPromptKeywords.ts matchesNegativeKeyword()
# ─────────────────────────────────────────
_FRUSTRATION_EN_RE = re.compile(
    r"\b(wtf|wth|ffs|broken|useless|terrible|stuck|loop|shit|fucking?|piece of crap)\b",
    re.IGNORECASE,
)
_FRUSTRATION_ZH_RE = re.compile(
    r"(一直|又出|重复|不行|坏了|崩了|死循环|烦死|垃圾|怎么又|又卡|又崩|又挂|还是不行)",
)

def matches_user_frustration(text: str) -> bool:
    """Return True if the user's message matches frustration patterns."""
    text = str(text or "").strip()
    return bool(_FRUSTRATION_EN_RE.search(text) or _FRUSTRATION_ZH_RE.search(text))


@dataclass
class SubTask:
    id: str
