        if name == "monster_primary_sheet.svg":
            return [
                "Broader torso than hero",
                "Weak-point glow callout",
                "Asymmetric reach limb rhythm",
                "Readable chase silhouette",
            ]
        if name == "weapon_primary_sheet.svg":
            return [
                "Barrel direction clearly readable",
                "Distinct grip / stock separation",
                "Muzzle origin stays explicit",
                "Material split: polymer / metal / emissive",
            ]
        return [
            "Primary combat lane + flank lane",
            "Mid-ground cover rhythm",
            "Large landmark for orientation",
            "Third-person camera-safe sightlines",
        ]

