    def _repair_imagegen_manifest(
        self,
        manifest_path: Path,
        *,
        goal: str,
        dependency_context: Optional[Dict[str, str]] = None,
    ) -> bool:
        data: Dict[str, Any] = {}
        if manifest_path.exists():
            try:
                data = json.loads(manifest_path.read_text(encoding="utf-8"))
                if not isinstance(data, dict):
                    data = {}
            except Exception:
                data = {}
        style_tokens = self._imagegen_style_lock_tokens(goal)
        data["goal"] = goal
        data["runtime_mode"] = task_classifier.game_runtime_mode(goal) or "3d_engine"
        data["asset_mode"] = task_classifier.game_asset_pipeline_mode(goal) or "3d"
        data["pack_origin"] = data.get("pack_origin") or "evermind_imagegen_fallback_core_pack"
        data["style_lock_tokens"] = data.get("style_lock_tokens") or style_tokens
        assets = data.get("assets")
        if not isinstance(assets, dict):
            assets = {}
        assets.setdefault("hero_player", {
            "brief": "character_hero_brief.md",
            "runtime_key": "hero_player",
            "replacement_kind": "character",
            "status": "design_pack",
        })
        required_domains = {name for name, _ in self._imagegen_required_asset_domains(goal)}
        if "enemy" in required_domains:
            assets.setdefault("enemy_primary", {
                "brief": "monster_primary_brief.md",
                "runtime_key": "enemy_primary",
                "replacement_kind": "enemy",
                "status": "design_pack",
            })
        if "weapon" in required_domains:
            assets.setdefault("weapon_primary", {
                "brief": "weapon_primary_brief.md",
                "runtime_key": "weapon_primary",
                "replacement_kind": "weapon",
                "status": "design_pack",
            })
        if "environment" in required_domains:
            assets.setdefault("environment_primary", {
                "brief": "environment_kit_brief.md",
                "runtime_key": "environment_primary",
                "replacement_kind": "environment",
                "status": "design_pack",
            })
        data["assets"] = assets
        data["licensed_sources"] = data.get("licensed_sources") or self._imagegen_licensed_sources(goal)
        if dependency_context and dependency_context.get("asset_sourcing_plan"):
            data["asset_sourcing_plan"] = data.get("asset_sourcing_plan") or dependency_context.get("asset_sourcing_plan")
        manifest_path.parent.mkdir(parents=True, exist_ok=True)
        manifest_path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
        return True

    def _repair_imagegen_core_pack(
        self,
        plan: Optional["Plan"],
        subtask: Optional[SubTask],
        *,
        prev_results: Optional[Dict[str, Any]] = None,
        existing_files: Optional[List[str]] = None,
    ) -> List[str]:
        goal = str(getattr(plan, "goal", "") or "")
        if not self._goal_needs_richer_imagegen_asset_pack(goal):
            return []
        asset_root = OUTPUT_DIR / "assets"
        asset_root.mkdir(parents=True, exist_ok=True)
        dependency_context = self._imagegen_dependency_context(plan, prev_results)
        repaired: List[str] = []
        existing = {
            self._normalize_generated_path(path): True
            for path in (existing_files or [])
            if self._normalize_generated_path(path)
        }
        for filename in self._imagegen_core_asset_filenames(goal):
            target = asset_root / filename
            normalized = self._normalize_generated_path(str(target))
            if filename == "manifest.json":
                needs_manifest = True
                if normalized and normalized in existing and self._imagegen_asset_has_meaningful_payload(normalized, goal):
                    needs_manifest = False
                if needs_manifest:
                    self._repair_imagegen_manifest(target, goal=goal, dependency_context=dependency_context)
                    repaired.append(str(target))
                continue
            if normalized and normalized in existing and self._imagegen_asset_has_meaningful_payload(normalized, goal):
                continue
            content = self._imagegen_synthesized_core_pack_content(
                filename,
                goal=goal,
                dependency_context=dependency_context,
            )
            if not content:
                continue
            target.write_text(content, encoding="utf-8")
            repaired.append(str(target))
        repaired = self._merge_generated_paths(repaired)
        validation_targets = self._merge_generated_paths(existing_files or [], repaired)
        healthy = [
            path for path in validation_targets
            if self._imagegen_asset_has_meaningful_payload(path, goal)
            and not Path(path).name.startswith(".")
        ]
        if self._imagegen_asset_bundle_incomplete_reason(healthy, goal):
            return []
        return repaired

    def _repair_imagegen_companion_docs(
        self,
        plan: Optional["Plan"],
        *,
        prev_results: Optional[Dict[str, Any]] = None,
        existing_files: Optional[List[str]] = None,
    ) -> List[str]:
        goal = str(getattr(plan, "goal", "") or "")
        if not self._goal_needs_richer_imagegen_asset_pack(goal):
            return []
        asset_root = OUTPUT_DIR / "assets"
        asset_root.mkdir(parents=True, exist_ok=True)
        dependency_context = self._imagegen_dependency_context(plan, prev_results)
        existing = {
            self._normalize_generated_path(path): True
            for path in (existing_files or [])
            if self._normalize_generated_path(path)
        }
        repaired: List[str] = []
        for filename in self._imagegen_companion_asset_filenames(goal):
            target = asset_root / filename
            normalized = self._normalize_generated_path(str(target))
            if normalized and normalized in existing and self._imagegen_asset_has_meaningful_payload(normalized, goal):
                continue
            if target.exists() and self._imagegen_asset_has_meaningful_payload(str(target), goal):
                continue
            content = self._imagegen_synthesized_core_pack_content(
                filename,
                goal=goal,
                dependency_context=dependency_context,
            )
            if not content:
                continue
            target.write_text(content, encoding="utf-8")
            repaired.append(str(target))
        return self._merge_generated_paths(repaired)

    def _delete_generated_files(self, files: List[str]) -> List[str]:
        deleted: List[str] = []
        seen: set[str] = set()
        for raw_path in files or []:
            normalized = self._normalize_generated_path(str(raw_path or ""))
            if not normalized or normalized in seen:
                continue
            seen.add(normalized)
            path = Path(normalized)
            try:
                if path.exists() and path.is_file():
                    path.unlink()
                    deleted.append(normalized)
            except Exception as exc:
                logger.warning("Failed to delete generated artifact %s: %s", path, exc)
        return deleted

    def __init__(self, ai_bridge, executor, on_event: Callable = None):
        self.ai_bridge = ai_bridge
        self.executor = executor
        self.on_event = on_event
        self.active_plan: Optional[Plan] = None
        self._cancel = False
        self._run_started_at: float = 0.0
        self.difficulty: str = "standard"
        # Reviewer rejection guard: configurable max rejections per run.
        self._reviewer_requeues: int = 0
        # P0-1: Canonical task/run bridge — set via run(canonical_context=...)
        self._canonical_ctx: Optional[Dict[str, Any]] = None
        # Maps orchestrator subtask ID → canonical NE ID (built after plan creation)
        self._subtask_ne_map: Dict[str, str] = {}
        # Immutable preview promotion: once a builder version passes quality, freeze it.
        self._stable_preview_path: Optional[Path] = None
        self._stable_preview_files: List[str] = []
        self._stable_preview_stage: str = ""

    def _materialize_runtime_assets_for_path(self, path: Path) -> List[str]:
        try:
            created = materialize_local_runtime_assets(
                path,
                task_type=getattr(self, "_current_task_type", "website"),
            )
            return [
                self._normalize_generated_path(str(item))
                for item in created
                if isinstance(item, Path) and item.exists()
            ]
        except Exception as exc:
            logger.warning("Failed to materialize local runtime assets for %s: %s", path, exc)
        return []

    def _ensure_runtime_assets_for_generated_files(self, files_created: List[str]) -> List[str]:
        merged: List[str] = []
        seen: set[str] = set()

        def _append(path_str: str) -> None:
            normalized = self._normalize_generated_path(path_str)
            if normalized and normalized not in seen:
                seen.add(normalized)
                merged.append(normalized)

        for item in files_created or []:
            _append(item)

        for item in list(merged):
            path = Path(item)
            if path.suffix.lower() not in (".html", ".htm"):
                continue
            for asset in self._materialize_runtime_assets_for_path(path):
                _append(asset)

        return merged

    def _prepare_builder_quality_files(self, files_created: List[str]) -> tuple[List[str], Optional[Path]]:
        prepared = self._merge_generated_paths(files_created or [])
        self._postprocess_builder_quality_candidates(prepared)
        prepared = self._ensure_runtime_assets_for_generated_files(prepared)

        html_files = [item for item in prepared if str(item).lower().endswith((".html", ".htm"))]
        preview_html = self._select_preview_artifact_for_files(prepared) if html_files else None
        if preview_html is None:
            return prepared, None

        preview_artifact = self._normalize_generated_path(str(preview_html))
        if preview_artifact and preview_artifact not in prepared:
            prepared.append(preview_artifact)
        self._postprocess_builder_quality_candidates([preview_artifact] if preview_artifact else [])
        prepared = self._ensure_runtime_assets_for_generated_files(prepared)
        return prepared, preview_html

    def _reset_builder_invalid_salvage_state(self, subtask: Optional[SubTask]) -> None:
        if not subtask or subtask.agent_type != "builder":
            return
        subtask.builder_invalid_salvage_signature = ""
        subtask.builder_invalid_salvage_repeat_count = 0
        subtask.builder_invalid_salvage_tripped = False
        subtask.builder_invalid_salvage_message = ""

    def _note_builder_invalid_salvage_pattern(
        self,
        subtask: Optional[SubTask],
        dropped_files: List[str],
    ) -> tuple[bool, str]:
        if not subtask or subtask.agent_type != "builder":
            return False, ""
        normalized = [str(item or "").strip() for item in (dropped_files or []) if str(item or "").strip()]
        if not normalized:
            self._reset_builder_invalid_salvage_state(subtask)
            return False, ""

        signature = " | ".join(normalized[:4])[:1000]
        if signature == subtask.builder_invalid_salvage_signature:
            subtask.builder_invalid_salvage_repeat_count = int(subtask.builder_invalid_salvage_repeat_count or 0) + 1
        else:
            subtask.builder_invalid_salvage_signature = signature
            subtask.builder_invalid_salvage_repeat_count = 1

        repeat_count = int(subtask.builder_invalid_salvage_repeat_count or 0)
        if repeat_count < 2:
            subtask.builder_invalid_salvage_tripped = False
            subtask.builder_invalid_salvage_message = ""
            return False, ""

        dropped_names = ", ".join(
            Path(str(item).split(" (", 1)[0]).name for item in normalized[:4]
        ) or "index.html"
        message = (
            "Repeated invalid salvaged HTML loop detected. "
            f"The same broken partial artifacts kept reappearing ({dropped_names}), so builder retry was stopped early "
            "instead of spinning until the global run timeout."
        )
        subtask.builder_invalid_salvage_tripped = True
        subtask.builder_invalid_salvage_message = message
        return True, message

    def _project_memory_roots(self, repo_root: str = "") -> List[Path]:
        roots: List[Path] = []
        seen: set[str] = set()
        candidates: List[str] = []
        normalized_repo_root = str(repo_root or "").strip()
        if normalized_repo_root:
            candidates.append(normalized_repo_root)
        if hasattr(self.ai_bridge, "config") and isinstance(self.ai_bridge.config, dict):
            workspace_root = str(self.ai_bridge.config.get("workspace", "") or "").strip()
            if workspace_root:
                candidates.append(workspace_root)
        for raw in candidates:
            try:
                resolved = Path(raw).expanduser().resolve()
            except Exception:
                continue
            key = str(resolved)
            if key in seen or not resolved.exists() or not resolved.is_dir():
                continue
            seen.add(key)
            roots.append(resolved)
        return roots

    def _project_memory_block(self, repo_root: str = "") -> str:
        entries: List[str] = []
        seen: set[str] = set()

        for root in self._project_memory_roots(repo_root):
            for name in PROJECT_MEMORY_FILENAMES:
                candidate = root / name
                key = str(candidate)
                if key in seen:
                    continue
                seen.add(key)
                entry = self._project_memory_entry(candidate, label=candidate.name)
                if not entry:
                    continue
                entries.append(entry)
                if len(entries) >= PROJECT_MEMORY_FILE_LIMIT:
                    break
            if len(entries) >= PROJECT_MEMORY_FILE_LIMIT:
                break

        if not entries:
            return ""
        return (
            "[Project Memory]\n"
            "Treat these repo-specific standing instructions as collaboration context unless they conflict with the current user request.\n\n"
            + "\n\n".join(entries)
        )

    def _project_memory_entry(self, candidate: Path, *, label: str = "") -> str:
        if not candidate.exists() or not candidate.is_file():
            return ""
        try:
            raw = candidate.read_text(encoding="utf-8", errors="ignore").strip()
        except Exception:
            return ""
        if not raw:
            return ""
        return (
            f"[{label or candidate.name}]\n"
            f"{self._condense_handoff_seed(raw, limit=PROJECT_MEMORY_SNIPPET_CHARS)}"
        )

    def _project_agent_brief_matches(self, agent_type: str, candidate: Path) -> bool:
        compact_agent = re.sub(r"[^a-z0-9]+", "", str(agent_type or "").strip().lower())
        if not compact_agent:
            return False
        compact_tokens = [
            re.sub(r"[^a-z0-9]+", "", token)
            for token in re.split(r"[^a-z0-9]+", candidate.stem.lower())
            if token
        ]
        if not compact_tokens:
            return False
        if any(token in PROJECT_AGENT_BRIEF_GENERIC_NAMES for token in compact_tokens):
            return True
        aliases = [compact_agent]
        aliases.extend(
            re.sub(r"[^a-z0-9]+", "", token)
            for token in PROJECT_AGENT_BRIEF_ALIASES.get(compact_agent, ())
            if str(token or "").strip()
        )
        for token in compact_tokens:
            for alias in aliases:
                if not alias:
                    continue
                if token == alias or token.startswith(alias) or alias.startswith(token):
                    return True
        return False

    def _project_agent_brief_block(self, agent_type: str, repo_root: str = "") -> str:
        normalized_agent = str(agent_type or "").strip().lower()
        if not normalized_agent:
            return ""

        entries: List[str] = []
        seen: set[str] = set()
        for root in self._project_memory_roots(repo_root):
            agent_dir = root / ".claude" / "agents"
            if not agent_dir.exists() or not agent_dir.is_dir():
                continue
            for candidate in sorted(root.glob(PROJECT_AGENT_BRIEF_GLOB)):
                key = str(candidate)
                if key in seen or not self._project_agent_brief_matches(normalized_agent, candidate):
                    continue
                seen.add(key)
                try:
                    label = candidate.relative_to(root).as_posix()
                except Exception:
                    label = candidate.name
                entry = self._project_memory_entry(candidate, label=label)
                if not entry:
                    continue
                entries.append(entry)
                if len(entries) >= PROJECT_AGENT_BRIEF_FILE_LIMIT:
                    break
            if len(entries) >= PROJECT_AGENT_BRIEF_FILE_LIMIT:
                break

        if not entries:
            return ""
        return (
            f"[Agent Brief — {normalized_agent}]\n"
            "Treat these role-specific repo instructions as standing guidance for this subtask unless the user explicitly overrides them.\n\n"
            + "\n\n".join(entries)
        )

    def _recent_related_run_memory_block(self) -> str:
        note = str(getattr(self, "_cross_session_memory_note", "") or "").strip()
        if not note:
            return ""
        return (
            "[Recent Related Run Memory]\n"
            "This is read-only handoff memory from a recent similar task started from a different session/client. "
            "Use it to preserve lessons learned after relay/session changes, but do NOT treat it as permission to reuse old artifacts unless this run explicitly asks to continue the same project.\n\n"
            + self._condense_handoff_seed(note, limit=RECENT_RUN_MEMORY_SNIPPET_CHARS)
        )

    def _task_backed_project_memory_block(self) -> str:
        digest = str((self._canonical_ctx or {}).get("project_memory_digest") or "").strip()
        if not digest:
            return ""
        source_task_id = str((self._canonical_ctx or {}).get("project_memory_source_task_id") or "").strip()
        header = "[Task Memory Digest]\n"
        if source_task_id:
            header += f"Source task: {source_task_id}\n"
        header += (
            "This is high-priority continuity context distilled from the latest known state of the same or closely related project. "
            "Use it to continue patching in place and avoid redoing solved work.\n\n"
        )
        return header + self._condense_handoff_seed(
            digest,
            limit=max(RECENT_RUN_MEMORY_SNIPPET_CHARS * 2, 1800),
        )

    def _continuation_patch_contract_block(self, agent_type: str) -> str:
        if not self._is_continuation_request(
            str(getattr(self, "_current_goal", "") or ""),
            getattr(self, "_current_conversation_history", []),
        ):
            return ""
        normalized = str(agent_type or "").strip().lower()
        lines = [
            "[Continuation / Patch Contract]",
            "This run is an in-place continuation on an existing project.",
            "Patch current files and current systems incrementally instead of re-conceiving the project from zero.",
            "Preserve the strongest implemented mechanics, flows, routes, art direction, and structure unless the user explicitly asked for a reset.",
            "When you change something, anchor the change to an existing file or subsystem and check regression risk before handing off.",
        ]
        if normalized == "merger":
            lines.append("Merge surgically: reconcile the existing live artifact plus both builder lanes instead of replacing everything with one lane's version.")
        elif normalized == "reviewer":
            lines.append("If you reject, produce a patch-oriented rollback report that tells the next node exactly what to edit and what to keep.")
        elif normalized == "tester":
            lines.append("Regression-check previously working behavior, not just the newest requested fix.")
        elif normalized == "analyst":
            lines.append("Research only the unresolved gap; do not restate the whole project from scratch.")
        elif normalized == "planner":
            lines.append("Plan around reuse, partial edits, and conflict-aware sequencing rather than greenfield delivery.")
        return "\n".join(lines)

    async def emit(self, event_type: str, data: Dict):
        if self.on_event:
            await self.on_event({"type": event_type, **data})

    # ── P0-1: Canonical NE bridge helpers ──────────
    def _ne_id_for_subtask(self, subtask_id: str) -> Optional[str]:
        """Return canonical NE ID for a subtask, or None if no bridge."""
        return self._subtask_ne_map.get(subtask_id)

    def _canonical_agent_type_for_node_key(self, node_key: str) -> str:
        return CANONICAL_NODE_KEY_TO_AGENT.get(str(node_key or "").strip(), "builder")

    def _default_node_label_for_key(self, node_key: str) -> str:
        key = str(node_key or "").strip().lower()
        if not key:
            return "Node"
        label_map = {
            "planner": "Planner",
            "analyst": "Analyst",
            "builder": "Builder",
            "builder1": "Builder 1",
            "builder2": "Builder 2",
            "merger": "Merger",
            "polisher": "Polisher",
            "reviewer": "Reviewer",
            "tester": "Tester",
            "deployer": "Deployer",
            "debugger": "Debugger",
            "scribe": "Scribe",
            "uidesign": "UI Design",
            "imagegen": "Image Gen",
            "spritesheet": "Spritesheet",
            "assetimport": "Asset Import",
        }
        if key in label_map:
            return label_map[key]
        pretty = re.sub(r"([a-z])([0-9])", r"\1 \2", key.replace("_", " ").replace("-", " "))
        return pretty.title()

    def _subtask_node_key(self, subtask: Optional[SubTask]) -> str:
        if not subtask:
            return ""
        explicit = str(getattr(subtask, "node_key", "") or "").strip()
        if explicit:
            return explicit
        return str(getattr(subtask, "agent_type", "") or "").strip()

    def _subtask_node_label(self, subtask: Optional[SubTask]) -> str:
        if not subtask:
            return ""
        explicit = str(getattr(subtask, "node_label", "") or "").strip()
        if explicit:
            return explicit
        return self._default_node_label_for_key(self._subtask_node_key(subtask))

    def _annotate_subtask_node_metadata(self, subtasks: List[SubTask]) -> List[SubTask]:
        if not subtasks:
            return subtasks
        builders = [st for st in subtasks if str(getattr(st, "agent_type", "") or "") == "builder"]
        total_builders = len(builders)
        builder_index = 0
        for st in subtasks:
            if str(getattr(st, "agent_type", "") or "") == "builder":
                builder_index += 1
                if not str(getattr(st, "node_key", "") or "").strip():
                    # v4.0 FIX: Changed >= 3 to >= 2 so that 2-builder plans
                    # (builder + merger) still assign node_key="merger" to the
                    # last builder when it matches merger semantics. Without
                    # this, the merger gets "builder2" and misses 600s timeout,
                    # merger_retry_note, and other merger-specific handling.
                    if total_builders >= 2 and builder_index == total_builders and self._builder_is_merger_like_subtask(st):
                        st.node_key = "merger"
                    elif total_builders >= 2:
                        st.node_key = f"builder{builder_index}"
                    else:
                        st.node_key = "builder"
                if not str(getattr(st, "node_label", "") or "").strip():
                    st.node_label = self._default_node_label_for_key(st.node_key)
                continue
            if not str(getattr(st, "node_key", "") or "").strip():
                st.node_key = str(getattr(st, "agent_type", "") or "").strip()
            if not str(getattr(st, "node_label", "") or "").strip():
                st.node_label = self._default_node_label_for_key(st.node_key)
        return subtasks

    def _map_subtasks_to_canonical_node_executions(
        self,
        plan: Plan,
        ne_list: List[Dict[str, Any]],
    ) -> Dict[str, str]:
        mapped: Dict[str, str] = {}
        used_ne_ids: set[str] = set()
        candidates_by_agent: Dict[str, List[Dict[str, Any]]] = {}
        agent_offsets: Dict[str, int] = {}

        for ne in ne_list or []:
            agent_type = self._canonical_agent_type_for_node_key(str(ne.get("node_key", "") or ""))
            candidates_by_agent.setdefault(agent_type, []).append(ne)

        for st in plan.subtasks:
            requested_node_key = self._subtask_node_key(st)
            if requested_node_key:
                for candidate in ne_list or []:
                    candidate_key = str(candidate.get("node_key") or "").strip()
                    ne_id = str(candidate.get("id") or "").strip()
                    if requested_node_key == candidate_key and ne_id and ne_id not in used_ne_ids:
                        mapped[st.id] = ne_id
                        used_ne_ids.add(ne_id)
                        break
                if st.id in mapped:
                    continue
            candidates = candidates_by_agent.get(str(getattr(st, "agent_type", "") or ""), [])
            next_index = int(agent_offsets.get(st.agent_type, 0) or 0)
            while next_index < len(candidates):
                candidate = candidates[next_index]
                next_index += 1
                ne_id = str(candidate.get("id") or "").strip()
                if not ne_id or ne_id in used_ne_ids:
                    continue
                mapped[st.id] = ne_id
                used_ne_ids.add(ne_id)
                agent_offsets[st.agent_type] = next_index
                break

        for i, st in enumerate(plan.subtasks):
            if st.id in mapped or i >= len(ne_list):
                continue
            fallback_ne_id = str(ne_list[i].get("id") or "").strip()
            if not fallback_ne_id or fallback_ne_id in used_ne_ids:
                continue
            mapped[st.id] = fallback_ne_id
            used_ne_ids.add(fallback_ne_id)

        return mapped

    def _runtime_server_module(self):
        """Resolve the live server module.

        When the backend is launched as `python server.py`, the running module is
        `__main__`, while `import server` creates a second module instance with an
        empty `connected_clients` set. That silently drops live WS broadcasts.
        """
        for module_name in ("__main__", "server"):
            module = sys.modules.get(module_name)
            if module and hasattr(module, "_broadcast_ws_event") and hasattr(module, "_transition_node_if_needed"):
                return module
        return None

    def _canonical_progress_for_status(self, status: str, explicit: Optional[int] = None) -> int:
        if explicit is not None:
            try:
                return max(0, min(100, int(explicit)))
            except Exception:
                pass
        normalized = str(status or "").strip().lower()
        if normalized == "running":
            return 5
        if normalized in {"passed", "failed", "blocked", "cancelled", "skipped"}:
            return 100
        return 0

    def _reset_progress_tracking(self, *subtask_ids: str) -> None:
        """Clear monotonic progress high-water marks for fresh queued/retry runs."""
        if not hasattr(self, "_progress_high_water"):
            return
        for subtask_id in subtask_ids:
            sid = str(subtask_id or "").strip()
            if sid:
                self._progress_high_water.pop(sid, None)

    def _append_ne_activity(
        self,
        subtask_id: str,
        message: str,
        *,
        entry_type: str = "info",
        timestamp_ms: Optional[int] = None,
    ) -> None:
        """Persist a human-readable activity entry for node detail/history hydration."""
        ne_id = self._ne_id_for_subtask(subtask_id)
        if not ne_id:
            return
        text = str(message or "").strip()
        if not text:
            return
        try:
            get_node_execution_store().update_node_execution(
                ne_id,
                {
                    "activity_log_append": [{
                        "ts": int(timestamp_ms or time.time() * 1000),
                        "msg": text[:600],
                        "type": str(entry_type or "info")[:16],
                    }],
                },
            )
        except Exception:
            pass

    def _visual_baseline_scope(self, goal: str) -> str:
        task_id = str((self._canonical_ctx or {}).get("task_id") or "").strip()
        if task_id:
            return f"task_{task_id}"
        normalized_goal = re.sub(r"\s+", " ", str(goal or "").strip().lower())
        if not normalized_goal:
            return "goal_default"
        return f"goal_{sha1(normalized_goal.encode('utf-8')).hexdigest()[:12]}"

    def _persist_visual_regression_artifact(self, subtask_id: str, gate_name: str, gate_result: Dict[str, Any]) -> None:
        visual = gate_result.get("visual_regression") if isinstance(gate_result, dict) else None
        if not isinstance(visual, dict):
            return
        status = str(visual.get("status", "") or "").strip().lower()
        summary = str(visual.get("summary", "") or "").strip()
        if status not in {"warn", "fail"} or not summary:
            return

        entry_type = "warn" if status == "warn" else "error"
        self._append_ne_activity(
            subtask_id,
            f"{gate_name} 视觉回归：{summary[:500]}",
            entry_type=entry_type,
        )

        run_id = str((self._canonical_ctx or {}).get("run_id") or "").strip()
        ne_id = self._ne_id_for_subtask(subtask_id) or ""
        if not run_id:
            return

        lines = [f"{gate_name} visual regression: {status.upper()}", summary]
        issues = visual.get("issues") if isinstance(visual.get("issues"), list) else []
        suggestions = visual.get("suggestions") if isinstance(visual.get("suggestions"), list) else []
        captures = visual.get("captures") if isinstance(visual.get("captures"), list) else []
        if issues:
            lines.append("Issues:")
            lines.extend(f"- {str(item)[:240]}" for item in issues[:6])
        if suggestions:
            lines.append("Suggestions:")
            lines.extend(f"- {str(item)[:240]}" for item in suggestions[:6])
        if captures:
            lines.append("Capture diffs:")
            for capture in captures[:4]:
                if not isinstance(capture, dict):
                    continue
                lines.append(
                    "- {name}: changed={changed} area={area} diff={diff}".format(
                        name=str(capture.get("name") or "capture")[:40],
                        changed=str(capture.get("changed_ratio", "")),
                        area=str(capture.get("diff_area_ratio", "")),
                        diff=str(capture.get("diff_path") or "")[:240],
                    )
                )

        artifact = get_artifact_store().save_artifact({
            "run_id": run_id,
            "node_execution_id": ne_id,
            "artifact_type": "diff_summary",
            "title": f"{gate_name} visual regression",
            "content": "\n".join(lines)[:50000],
            "metadata": {
                "status": status,
                "summary": summary,
                "preview_url": gate_result.get("preview_url"),
                "captures": captures[:6],
                "scope_key": visual.get("scope_key", ""),
                "page_key": visual.get("page_key", ""),
            },
        })
        if ne_id and artifact.get("id"):
            try:
                get_node_execution_store().update_node_execution(ne_id, {"artifact_ids": [artifact["id"]]})
            except Exception:
                pass

    def _persist_node_artifact(
        self,
        subtask_id: str,
        *,
        artifact_type: str,
        title: str,
        path: str = "",
        content: str = "",
        metadata: Optional[Dict[str, Any]] = None,
        bucket: str = "",
    ) -> Optional[Dict[str, Any]]:
        run_id = str((self._canonical_ctx or {}).get("run_id") or "").strip()
        ne_id = self._ne_id_for_subtask(subtask_id) or ""
        if not run_id:
            return None
        artifact_data = {
            "run_id": run_id,
            "node_execution_id": ne_id,
            "artifact_type": artifact_type,
            "title": title,
            "path": path,
            "content": content,
            "metadata": metadata or {},
        }
        # For report/handoff artifacts, use upsert to replace stale reports
        # when a node is re-run after rejection
        store = get_artifact_store()
        if bucket in ("report", "handoff") and ne_id:
            artifact = store.upsert_by_node_and_type(artifact_data)
        else:
            artifact = store.save_artifact(artifact_data)
        if ne_id and artifact.get("id"):
            try:
                update_data: Dict[str, Any] = {"artifact_ids": [artifact["id"]]}
                if bucket == "report":
                    update_data["report_artifact_ids"] = [artifact["id"]]
                elif bucket == "handoff":
                    update_data["handoff_artifact_ids"] = [artifact["id"]]
                if artifact_type == "execution_dossier":
                    update_data["dossier_artifact_id"] = artifact["id"]
                    update_data["report_artifact_ids"] = [artifact["id"]]
                elif artifact_type == "node_summary_report":
                    update_data["summary_artifact_id"] = artifact["id"]
                    update_data["report_artifact_ids"] = [artifact["id"]]
                elif artifact_type == "review_rollback_report":
                    update_data["latest_review_report_artifact_id"] = artifact["id"]
                    update_data["report_artifact_ids"] = [artifact["id"]]
                elif artifact_type == "merge_manifest":
                    update_data["latest_merge_manifest_artifact_id"] = artifact["id"]
                    update_data["handoff_artifact_ids"] = [artifact["id"]]
                elif artifact_type == "deployment_receipt":
                    update_data["latest_deployment_receipt_artifact_id"] = artifact["id"]
                    update_data["report_artifact_ids"] = [artifact["id"]]
                get_node_execution_store().update_node_execution(ne_id, update_data)
            except Exception:
                pass
        return artifact

    def _safe_report_slug(self, value: str, *, default: str = "report", limit: int = 80) -> str:
        slug = re.sub(r"[^a-zA-Z0-9._-]+", "-", str(value or "").strip().lower()).strip("-.")
        if not slug:
            slug = default
        return slug[:limit]

    def _node_report_root(self, repo_root: str = "") -> Path:
        base_dir = Path(str(repo_root or "").strip()).expanduser() if str(repo_root or "").strip() else None
        if not base_dir or not str(base_dir):
            cfg = self._runtime_config() or {}
            workspace = str(cfg.get("workspace") or "").strip() if isinstance(cfg, dict) else ""
            base_dir = Path(workspace).expanduser() if workspace else Path.home()
        if not base_dir.exists():
            base_dir = Path.home()
        report_dir = base_dir / ".evermind" / "reports"
        report_dir.mkdir(parents=True, exist_ok=True)
        return report_dir

    def _write_node_report_file(
        self,
        *,
        subtask_id: str,
        repo_root: str = "",
        artifact_type: str,
        filename_tag: str,
        content: str,
    ) -> str:
        run_id = str((self._canonical_ctx or {}).get("run_id") or "").strip() or "run"
        ne_id = self._ne_id_for_subtask(subtask_id) or subtask_id or "node"
        try:
            report_dir = self._node_report_root(repo_root=repo_root) / self._safe_report_slug(run_id, default="run", limit=48)
            report_dir.mkdir(parents=True, exist_ok=True)
            filename = (
                f"{self._safe_report_slug(filename_tag, default='report', limit=36)}_"
                f"{self._safe_report_slug(ne_id, default='node', limit=24)}_"
                f"{self._safe_report_slug(artifact_type, default='artifact', limit=24)}.md"
            )
            file_path = report_dir / filename
            file_path.write_text((str(content or "").rstrip() + "\n"), encoding="utf-8")
            return str(file_path)
        except (OSError, PermissionError) as exc:
            logger.warning("Failed to write node report file: %s", exc)
            return ""

    def _coerce_report_list(self, value: Any, *, limit: int = 12, item_limit: int = 240) -> List[str]:
        if isinstance(value, list):
            items = value
        elif value in (None, ""):
            items = []
        else:
            items = [value]
        normalized: List[str] = []
        seen: set[str] = set()
        for item in items:
            text = re.sub(r"\s+", " ", str(item or "")).strip(" -")
            if not text:
                continue
            clipped = text[:item_limit]
            lowered = clipped.lower()
            if lowered in seen:
                continue
            seen.add(lowered)
            normalized.append(clipped)
            if len(normalized) >= limit:
                break
        return normalized

    def _clean_execution_trace(self, activity_lines: List[str]) -> List[str]:
        """Clean execution trace: filter noise, deduplicate, and make human-readable.

        Removes low-level implementation-detail entries (variable names, logic snippets),
        deduplicates similar messages, and produces a clean timeline.
        """
        # Patterns that indicate low-level noise (variable names, code fragments)
        _noise_patterns = re.compile(
            r'正在实现\s+\w+\s+逻辑'  # "正在实现 moveDirection 逻辑"
            r'|正在实现\s+\w+Position'
            r'|正在实现\s+\w+States'
            r'|正在实现\s+\w+Direction'
            r'|正在实现\s+\w+Spherical'
            r'|正在实现\s+\w+Muzzle'
            r'|正在实现\s+\w+Spawn'
            r'|正在实现\s+\w+Distance'
            r'|正在实现\s+\w+Animation',
            re.IGNORECASE,
        )
        # Group similar "草稿进展" entries
        _draft_pattern = re.compile(r'草稿进展[：:]?\s*正在实现', re.IGNORECASE)

        cleaned: List[str] = []
        seen_msgs: set = set()
        draft_count = 0

        for line in activity_lines:
            # Extract message part after the timestamp and type
            msg_match = re.search(r'\)\s+(.+)$', line)
            msg = msg_match.group(1).strip() if msg_match else line.strip()

            # Skip noise
            if _noise_patterns.search(msg):
                draft_count += 1
                continue

            # Count and collapse draft progress entries
            if _draft_pattern.search(msg):
                draft_count += 1
                continue

            # Deduplicate similar messages
            msg_key = re.sub(r'\d+', 'N', msg.lower())[:80]
            if msg_key in seen_msgs:
                continue
            seen_msgs.add(msg_key)

            cleaned.append(line)

        # If we collapsed draft entries, add a summary line
        if draft_count > 0 and cleaned:
            # Insert draft summary before the last entries
            ts_match = re.search(r'\[([\d:]+)\]', cleaned[0]) if cleaned else None
            ts = ts_match.group(1) if ts_match else "--:--:--"
            cleaned.insert(0, f"- [{ts}] (info) 代码草稿阶段：迭代了 {draft_count} 个代码模块的实现细节")

        return cleaned

    # ── AI Narrative Report Writer (方案 B) ──

    # ── Structured Output Schemas (ported from Pydantic AI) ──

    _PLANNER_BLUEPRINT_SCHEMA: Dict[str, Any] = {
        "type": "object",
        "properties": {
            "architecture": {"type": "string"},
            "modules": {"type": "array", "items": {"type": "string"}},
            "execution_order": {"type": "array", "items": {"type": "string"}},
            "key_dependencies": {"type": "array", "items": {"type": "string"}},
            "node_briefs": {"type": "object"},
            "builder_ownership": {"type": "object"},
            "subsystem_contracts": {"type": "object"},
            "acceptance_checks": {"type": "array"},
            "rollback_triggers": {"type": "array"},
        },
        "required": ["architecture", "modules"],
    }

