    def _humanize_output_summary(self, agent_type: str, raw_output: str, success: bool, files_created: list = None) -> str:
        """Generate a rich, content-aware summary from raw agent output — never use static templates."""
        if not success:
            err = raw_output[:200] if raw_output else "未知错误"
            return f"执行失败：{err}"

        lower = (raw_output or "").lower()
        lines_all = (raw_output or "").strip().split('\n') if raw_output else []
        file_names = [f.split('/')[-1] for f in (files_created or []) if f] if files_created else []

        if agent_type == "planner":
            # Extract real plan metrics from output
            parts = ["任务规划完成"]
            node_count = len(re.findall(r'(?:node|subtask|子任务|节点)\b', lower))
            if node_count > 0:
                parts.append(f"规划了 {node_count} 个执行节点")
            # Detect mode
            for mode in ("pro", "deep", "simple", "standard"):
                if mode in lower:
                    parts.append(f"模式: {mode}")
                    break
            # Extract key roles mentioned
            roles_found = []
            for r in ("analyst", "builder", "merger", "reviewer", "tester", "debugger", "imagegen"):
                if r in lower:
                    roles_found.append(r)
            if roles_found:
                parts.append(f"分工: {' → '.join(roles_found[:6])}")
            # Detect parallel builders
            if lower.count("builder") >= 2 or "parallel" in lower or "并行" in lower:
                parts.append("含并行构建分支")
            return "，".join(parts) + "。"

        if agent_type == "analyst":
            parts = ["分析完成"]
            # Count references
            ref_count = sum(1 for l in lines_all if any(k in l.lower() for k in ('http', 'www', 'github.com', '参考')))
            if ref_count > 0:
                parts.append(f"调研了 {min(ref_count, 10)} 个参考案例")
            # Extract tech recommendations
            tech_found = []
            for tech in ("three.js", "webgl", "canvas", "react", "vue", "svelte", "tailwind",
                         "gsap", "anime.js", "pixi", "phaser", "babylon", "p5.js"):
                if tech in lower:
                    tech_found.append(tech)
            if tech_found:
                parts.append(f"推荐技术栈: {', '.join(tech_found[:4])}")
            # Detect architecture analysis
            for kw, label in [("layout", "布局模式"), ("color", "配色方案"), ("typography", "排版体系"),
                              ("animation", "动效策略"), ("responsive", "响应式方案"), ("feasib", "可行性评级")]:
                if kw in lower:
                    parts.append(f"分析了{label}")
            # Count handoff sections
            handoff_count = len(re.findall(r'builder[_\s]*\d*[_\s]*handoff|交接', lower))
            if handoff_count > 0:
                parts.append(f"生成了 {handoff_count} 份 Builder 交接文档")
            if file_names:
                parts.append(f"输出 {len(file_names)} 个文件")
            return "，".join(parts[:5]) + "。"

        if agent_type == "builder":
            parts = ["构建完成"]
            if file_names:
                parts.append(f"生成了 {', '.join(file_names[:3])}")
            # Extract what was actually built
            modules_built = []
            for kw, label in [("player", "玩家控制"), ("camera", "镜头系统"), ("weapon", "武器系统"),
                              ("enemy", "敌人AI"), ("collision", "碰撞检测"), ("particle", "粒子效果"),
                              ("hud", "HUD界面"), ("score", "计分系统"), ("level", "关卡逻辑"),
                              ("inventory", "背包系统"), ("dialog", "对话系统"), ("navigation", "导航"),
                              ("animation", "动画系统"), ("physics", "物理引擎"), ("sound", "音效系统"),
                              ("game loop", "游戏循环"), ("state machine", "状态机"), ("renderer", "渲染器"),
                              ("responsive", "响应式布局"), ("carousel", "轮播组件"), ("form", "表单组件"),
                              ("modal", "弹窗组件"), ("scroll", "滚动效果"), ("chart", "图表")]:
                if kw in lower:
                    modules_built.append(label)
            if modules_built:
                parts.append(f"实现了 {'/'.join(modules_built[:5])}")
            # Count functions
            func_count = len(re.findall(r'(?:function\s+\w+|const\s+\w+\s*=\s*(?:\([^)]*\)|\w+)\s*=>|class\s+\w+)', raw_output or ""))
            if func_count > 3:
                parts.append(f"含 {func_count} 个函数/类")
            # Code size hint
            total_lines = sum(1 for l in lines_all if l.strip())
            if total_lines > 100:
                parts.append(f"~{total_lines} 行有效输出")
            return "，".join(parts[:5]) + "。"

        if agent_type == "merger":
            parts = ["合并完成"]
            if file_names:
                parts.append(f"输出了 {', '.join(file_names[:3])}")
            # Detect merge strategy
            if "builder" in lower and ("1" in lower or "2" in lower):
                b1 = "builder-1" in lower or "builder_1" in lower or "builder 1" in lower
                b2 = "builder-2" in lower or "builder_2" in lower or "builder 2" in lower
                if b1 and b2:
                    parts.append("整合了双 Builder 产物")
                elif b1:
                    parts.append("基于 Builder-1 产物整合")
            if any(k in lower for k in ("conflict", "冲突", "dedup", "去重")):
                parts.append("解决了模块冲突")
            if any(k in lower for k in ("refactor", "重构", "restructur")):
                parts.append("进行了结构重构")
            return "，".join(parts[:4]) + "，保留了并行构建中的有效实现。"

        if agent_type == "polisher":
            improvements = []
            for kw, label in [("animation", "动效"), ("transition", "过渡"), ("typography", "排版"),
                              ("spacing", "留白"), ("scroll", "滚动"), ("color", "配色"),
                              ("shadow", "阴影"), ("border", "边框"), ("gradient", "渐变"),
                              ("hover", "悬浮效果"), ("loading", "加载动画"), ("accessibility", "无障碍")]:
                if kw in lower:
                    improvements.append(label)
            detail = f"（强化了{'、'.join(improvements[:5])}）" if improvements else ""
            return f"精修完成，已对现有页面做成品级抛光{detail}。"

        if agent_type == "reviewer":
            # Extract real review findings
            parts = []
            if 'approved' in lower or '通过' in lower:
                parts.append("审查通过")
            elif 'rejected' in lower or '不通过' in lower:
                parts.append("审查未通过")
            else:
                parts.append("审查完成")
            # Count issues/strengths
            issue_count = len(re.findall(r'(?:issue|bug|问题|缺陷|fix|修复)\b', lower))
            strength_count = len(re.findall(r'(?:strength|优点|强项|good|excellent|优秀)\b', lower))
            if strength_count > 0:
                parts.append(f"肯定了 {strength_count} 项强项")
            if issue_count > 0:
                parts.append(f"发现 {issue_count} 个待改进项")
            # Detect specific review areas
            areas = []
            for kw, label in [("visual", "视觉"), ("interact", "交互"), ("performance", "性能"),
                              ("accessibility", "无障碍"), ("responsive", "响应式"), ("code quality", "代码质量")]:
                if kw in lower:
                    areas.append(label)
            if areas:
                parts.append(f"覆盖了{'、'.join(areas[:3])}维度")
            return "，".join(parts[:4]) + "。"

        if agent_type == "imagegen":
            created = [Path(f).name for f in (files_created or []) if str(f or "").strip()]
            parts = []
            if created:
                image_exts = {".png", ".jpg", ".jpeg", ".webp", ".gif", ".bmp", ".svg", ".avif"}
                images = [n for n in created if Path(n).suffix.lower() in image_exts]
                docs = [n for n in created if Path(n).suffix.lower() in {".md", ".txt", ".json", ".yaml"}]
                if images:
                    # Categorize by filename patterns
                    categories = set()
                    for img in images:
                        il = img.lower()
                        for kw, cat in [("character", "角色"), ("hero", "英雄"), ("monster", "怪物"),
                                        ("enemy", "敌人"), ("weapon", "武器"), ("environment", "环境"),
                                        ("scene", "场景"), ("ui", "UI"), ("icon", "图标")]:
                            if kw in il:
                                categories.add(cat)
                    parts.append(f"生成了 {len(images)} 张视觉资产")
                    if categories:
                        parts.append(f"涵盖{'、'.join(sorted(categories)[:4])}类别")
                if docs:
                    # Categorize doc types
                    doc_types = set()
                    for d in docs:
                        dl = d.lower()
                        for kw, dt in [("brief", "设计规范"), ("manifest", "资产清单"), ("style", "风格定义"),
                                       ("visual", "视觉目标"), ("prompt", "生成提示词"), ("material", "材质说明"),
                                       ("source", "资源来源"), ("orthographic", "正交提示词")]:
                            if kw in dl:
                                doc_types.add(dt)
                    if doc_types:
                        parts.append(f"配套{'、'.join(sorted(doc_types)[:3])}文档")
                    else:
                        parts.append(f"配套 {len(docs)} 份说明文档")
                if not parts:
                    parts.append(f"输出了 {len(created)} 个文件")
            else:
                if "prompt" in lower or "style-lock" in lower:
                    parts.append("输出了图像提示词包与风格约束")
                else:
                    parts.append("图像生成阶段完成")
            return "，".join(parts[:4]) + "。"

        if agent_type == "spritesheet":
            parts = ["资产包规划完成"]
            if file_names:
                parts.append(f"输出了 {', '.join(file_names[:3])}")
            for kw, label in [("animation", "动画片段"), ("sprite", "精灵图"), ("atlas", "图集"),
                              ("naming", "命名规范"), ("export", "导出约束")]:
                if kw in lower:
                    parts.append(f"包含{label}定义")
            return "，".join(parts[:4]) + "。"

        if agent_type == "assetimport":
            parts = ["资产导入方案完成"]
            if file_names:
                parts.append(f"输出了 {', '.join(file_names[:3])}")
            for kw, label in [("manifest", "清单索引"), ("replacement", "替换锚点"), ("lod", "LOD策略"),
                              ("compress", "压缩方案"), ("fallback", "回退策略"), ("gltf", "glTF导入")]:
                if kw in lower:
                    parts.append(f"定义了{label}")
            return "，".join(parts[:4]) + "。"

        if agent_type == "tester":
            parts = []
            if 'pass' in lower or '通过' in lower:
                parts.append("测试通过")
            elif 'fail' in lower or '失败' in lower:
                parts.append("测试发现问题")
            else:
                parts.append("测试完成")
            # Count test cases
            test_count = len(re.findall(r'(?:test case|测试用例|✓|✗|PASS|FAIL)', raw_output or "", re.IGNORECASE))
            if test_count > 0:
                parts.append(f"执行了 {test_count} 个检查点")
            # Detect test areas
            for kw, label in [("screenshot", "截图验证"), ("browser", "浏览器测试"), ("interaction", "交互测试"),
                              ("visual", "视觉检查"), ("performance", "性能测试"), ("mobile", "移动端测试"),
                              ("gameplay", "游玩测试"), ("play", "实际游玩")]:
                if kw in lower:
                    parts.append(f"含{label}")
            return "，".join(parts[:4]) + "。"

        if agent_type == "debugger":
            parts = ["调试完成"]
            fix_count = len(re.findall(r'(?:fix|修复|patch|补丁)\b', lower))
            if fix_count > 0:
                parts.append(f"修复了 {fix_count} 个问题")
            if file_names:
                parts.append(f"修改了 {', '.join(file_names[:3])}")
            return "，".join(parts[:3]) + "。"

        if agent_type == "deployer":
            parts = ["部署完成"]
            if any(k in lower for k in ("url", "http", "preview", "预览")):
                parts.append("预览链接已生成")
            if file_names:
                parts.append(f"发布了 {', '.join(file_names[:2])}")
            return "，".join(parts[:3]) + "。"

        return f"{agent_type} 执行完成。"

    def _update_ne_failure_details(
        self,
        subtask_id: str,
        *,
        output_summary: str,
        error_message: str,
        tokens_used: int = 0,
        cost: float = 0.0,
        persist_error_message: bool = False,
    ) -> None:
        """Update canonical node details for a failed attempt without forcing terminal status."""
        ne_id = self._ne_id_for_subtask(subtask_id)
        if not ne_id:
            return
        try:
            nes = get_node_execution_store()
            update_data: Dict[str, Any] = {
                "output_summary": str(output_summary or "")[:2000],
                "phase": "attempt_failed",
            }
            if persist_error_message:
                update_data["error_message"] = str(error_message or "")[:500]
            if int(tokens_used or 0) > 0:
                update_data["tokens_used"] = int(tokens_used)
            if float(cost or 0.0) > 0:
                update_data["cost"] = float(cost)
            nes.update_node_execution(ne_id, update_data)
        except Exception:
            pass

    def _normalize_html_artifact(self, html_code: str, task_type: str = "website") -> str:
        """Auto-close truncated HTML so quality gates can validate the saved artifact.

        For game/creative tasks, also detect if the JavaScript was critically
        truncated (e.g. missing gameLoop, unclosed functions) and log a warning
        so the orchestrator can mark the artifact as incomplete.
        """
        normalized = str(html_code or "").strip()
        if (
            normalized.count("\\n") >= 4
            and normalized.count("\n") <= 1
            and ("<html" in normalized.lower() or "<!doctype" in normalized.lower())
        ):
            decoded = normalized
            if len(decoded) >= 2 and decoded[0] == decoded[-1] and decoded[0] in {"\"", "'"}:
                decoded = decoded[1:-1]
            decoded = (
                decoded
                .replace("\\r\\n", "\n")
                .replace("\\n", "\n")
                .replace("\\t", "\t")
                .replace("\\/", "/")
                .replace('\\"', '"')
                .replace("\\'", "'")
            ).strip()
            if "<html" in decoded.lower() or "<!doctype" in decoded.lower():
                normalized = decoded
                logger.info("Decoded escaped HTML artifact before structural repair (%d chars)", len(normalized))
        repaired = repair_html_structure(normalized)
        if repaired != normalized:
            normalized = repaired
            logger.info(f"Auto-closed truncated HTML ({len(normalized)} chars)")

        # Detect critically truncated JS in game artifacts
        if task_type in ("game", "creative"):
            lower_norm = normalized.lower()
            script_opens = lower_norm.count("<script")
            script_closes = lower_norm.count("</script>")
            if script_opens > script_closes:
                logger.warning(
                    "Truncated game JS detected: %d <script> opens but only %d </script> closes — "
                    "game code is likely incomplete",
                    script_opens,
                    script_closes,
                )
            # Check for critical game functions that should exist
            critical_game_funcs = ("gameloop", "animate", "requestanimationframe", "update")
            has_any_loop = any(func in lower_norm for func in critical_game_funcs)
            if not has_any_loop and "<canvas" in lower_norm:
                logger.warning(
                    "Truncated game JS detected: no game loop function found "
                    "(gameLoop/animate/requestAnimationFrame/update) — game is unplayable"
                )

        return normalized

    def _parse_code_block_header(self, header: str) -> tuple[str, Optional[Path]]:
        raw = str(header or "").strip()
        if not raw:
            return "txt", None

        tokens = [token.strip().strip(",") for token in raw.split() if token.strip()]
        lang = ""
        filename = ""
        if tokens and re.fullmatch(r"[\w+-]+", tokens[0]):
            lang = tokens.pop(0).lower()

        for token in tokens:
            cleaned = token.strip().strip("\"'`")
            lower = cleaned.lower()
            if lower.startswith(("file=", "filename=", "path=")):
                filename = cleaned.split("=", 1)[1].strip().strip("\"'`")
                continue
            if lower.startswith(("file:", "filename:", "path:")):
                filename = cleaned.split(":", 1)[1].strip().strip("\"'`")
                continue
            if "." in cleaned:
                filename = cleaned

        def _sanitize_rel_path(candidate: Path) -> Optional[Path]:
            parts = [str(part).strip() for part in candidate.parts if str(part).strip()]
            if parts and re.fullmatch(r"task_\d+", parts[0], re.IGNORECASE):
                parts = parts[1:]
            if not parts or any(part in {"", ".", ".."} for part in parts):
                return None
            return Path(*parts)

        rel_path: Optional[Path] = None
        if filename:
            candidate = Path(filename)
            if candidate.is_absolute():
                try:
                    output_root = OUTPUT_DIR.resolve()
                    resolved_candidate = candidate.resolve()
                    if resolved_candidate == output_root or output_root in resolved_candidate.parents:
                        rel_candidate = resolved_candidate.relative_to(output_root)
                        rel_path = _sanitize_rel_path(rel_candidate)
                except Exception:
                    rel_path = None
            elif candidate.parts:
                rel_path = _sanitize_rel_path(candidate)

        if not lang and rel_path is not None:
            lang = rel_path.suffix.lower().lstrip(".")
        return (lang or "txt"), rel_path

    def _save_extracted_code_block(
        self,
        *,
        task_dir: Path,
        rel_path: Path,
        code: str,
        files: List[str],
        allow_root_index_copy: bool,
        allow_root_shared_asset_write: bool = True,
        allowed_html_targets: Optional[set[str]] = None,
        is_retry: bool = False,
        merge_owner: Optional[str] = None,
        output_root: Optional[Path] = None,
    ) -> None:
        stage_only_root_html = bool(output_root is not None and output_root != OUTPUT_DIR)
        if rel_path.suffix.lower() in (".html", ".htm"):
            if allowed_html_targets and rel_path.name not in allowed_html_targets:
                logger.info(f"Skipping extracted HTML block outside assigned targets: {rel_path.name}")
                return
            if rel_path.name == "index.html" and not allow_root_index_copy and not stage_only_root_html:
                logger.info("Skipping extracted secondary builder index.html block")
                return
        task_type = getattr(self, "_current_task_type", "website")
        code = postprocess_generated_text(code, filename=rel_path.name, task_type=task_type)
        target_root = output_root or OUTPUT_DIR
        target = target_root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        shared_asset_names = {"styles.css", "app.js", "style.css", "main.css", "main.js", "script.js"}
        if (
            not allow_root_shared_asset_write
            and len(rel_path.parts) == 1
            and rel_path.name.lower() in shared_asset_names
        ):
            logger.info("Skipping root shared asset block for secondary builder: %s", rel_path.name)
            return

        def _shared_asset_markers(owner: str) -> tuple[str, str]:
            safe_owner = re.sub(r"[^A-Za-z0-9_.:-]+", "-", str(owner or "").strip()) or "builder"
            if rel_path.suffix.lower() == ".css":
                return (
                    f"/* ── Builder Asset Start: {safe_owner} ── */",
                    f"/* ── Builder Asset End: {safe_owner} ── */",
                )
            return (
                f"// ── Builder Asset Start: {safe_owner} ──",
                f"// ── Builder Asset End: {safe_owner} ──",
            )

        def _render_shared_asset_section(owner: str, payload: str) -> str:
            start, end = _shared_asset_markers(owner)
            return f"{start}\n{payload.strip()}\n{end}"

        def _shared_asset_section_pattern(owner: Optional[str] = None) -> re.Pattern[str]:
            if rel_path.suffix.lower() == ".css":
                if owner:
                    start, end = _shared_asset_markers(owner)
                    return re.compile(
                        re.escape(start) + r"\s*(?P<payload>.*?)\s*" + re.escape(end),
                        re.DOTALL,
                    )
                return re.compile(
                    r"/\*\s*── Builder Asset Start: [^*]+── \*/\s*(?P<payload>.*?)\s*/\*\s*── Builder Asset End: [^*]+── \*/",
                    re.DOTALL,
                )
            if owner:
                start, end = _shared_asset_markers(owner)
                return re.compile(
                    re.escape(start) + r"\s*(?P<payload>.*?)\s*" + re.escape(end),
                    re.DOTALL,
                )
            return re.compile(
                r"//\s*── Builder Asset Start: .+?──\s*(?P<payload>.*?)\s*//\s*── Builder Asset End: .+?──",
                re.DOTALL,
            )

        def _extract_owner_scoped_payload(payload: str, owner: str) -> Optional[str]:
            match = _shared_asset_section_pattern(owner).search(str(payload or ""))
            extracted = str(match.group("payload") or "").strip() if match else ""
            return extracted or None

        def _strip_shared_asset_wrappers(payload: str) -> str:
            text = str(payload or "")
            text = _shared_asset_section_pattern().sub(
                lambda match: str(match.group("payload") or "").strip() + "\n",
                text,
            )
            text = re.sub(
                r"(?:/\*\s*── Builder Merge: Additional Styles ── \*/|//\s*── Builder Merge: Additional Scripts ──)\s*",
                "",
                text,
                flags=re.IGNORECASE,
            )
            return text.strip()

        def _upsert_shared_asset_section(existing: str, owner: str, payload: str) -> tuple[str, str]:
            marker_token = "Builder Asset Start:"
            start, end = _shared_asset_markers(owner)
            replacement = _render_shared_asset_section(owner, payload)
            normalized_existing = str(existing or "").strip()
            normalized_payload = str(payload or "").strip()

            if not normalized_existing:
                return replacement, "created"

            base_text = existing
            if marker_token not in base_text:
                if normalized_existing == normalized_payload:
                    return base_text, "duplicate"
                base_text = _render_shared_asset_section("legacy-base", existing)

            section_pattern = re.compile(
                re.escape(start) + r".*?" + re.escape(end),
                re.DOTALL,
            )
            updated, replaced = section_pattern.subn(replacement, base_text, count=1)
            if replaced:
                if updated == base_text:
                    return base_text, "duplicate"
                return updated, "replaced"

            if normalized_payload and normalized_payload in base_text:
                return base_text, "duplicate"

            return base_text.rstrip() + "\n\n" + replacement, "appended"

        if rel_path.name.lower() in shared_asset_names and merge_owner:
            try:
                existing = target.read_text(encoding="utf-8", errors="ignore") if target.exists() else ""
                owner_payload = code
                if is_retry:
                    extracted_payload = _extract_owner_scoped_payload(code, merge_owner)
                    if extracted_payload:
                        owner_payload = extracted_payload
                    else:
                        owner_payload = _strip_shared_asset_wrappers(code) or code
                merged, merge_state = _upsert_shared_asset_section(existing, merge_owner, owner_payload)
                if target.exists() and merged == existing:
                    logger.info("Skipping duplicate shared asset section for %s (%s)", target.name, merge_owner)
                    files.append(str(target))
                    return
                target.write_text(merged, encoding="utf-8")
                self._materialize_runtime_assets_for_path(target)
                logger.info(
                    "%s shared asset %s for %s (%d chars)",
                    merge_state.capitalize(),
                    target.name,
                    merge_owner,
                    len(merged),
                )
                files.append(str(target))
                return
            except Exception as merge_err:
                logger.warning(
                    "Owner-scoped shared asset merge failed for %s (%s), falling back: %s",
                    target.name,
                    merge_owner,
                    merge_err,
                )

        if (
            rel_path.name.lower() in shared_asset_names
            and target.exists()
            and target.stat().st_size > 100
            and not is_retry
        ):
            try:
                existing = target.read_text(encoding="utf-8", errors="ignore")
                normalized_existing = existing.strip()
                normalized_new = code.strip()
                if normalized_new and normalized_new in existing:
                    logger.info("Skipping duplicate shared asset append for %s", target.name)
                    files.append(str(target))
                    return
                # Cap: do not merge more than 3 sections to prevent runaway growth
                merge_marker = "Builder Merge:"
                if existing.count(merge_marker) >= 3:
                    logger.info(
                        "Shared asset %s already has %d merge sections; overwriting to prevent runaway growth",
                        target.name, existing.count(merge_marker),
                    )
                elif normalized_new != normalized_existing and len(normalized_new) > 50:
                    # For CSS: concatenate with a separator comment
                    # For JS: concatenate with a safety separator
                    if rel_path.suffix.lower() == ".css":
                        merged = existing.rstrip() + "\n\n/* ── Builder Merge: Additional Styles ── */\n\n" + code.lstrip()
                    else:
                        merged = existing.rstrip() + "\n\n// ── Builder Merge: Additional Scripts ──\n\n" + code.lstrip()
                    target.write_text(merged, encoding="utf-8")
                    self._materialize_runtime_assets_for_path(target)
                    logger.info(
                        "Merged shared asset %s: existing=%d + new=%d = %d chars",
                        target.name, len(existing), len(code), len(merged),
                    )
                    files.append(str(target))
                    return
            except Exception as merge_err:
                logger.warning("Shared asset merge failed for %s, falling back to overwrite: %s", target.name, merge_err)
        target.write_text(code, encoding="utf-8")
        self._materialize_runtime_assets_for_path(target)
        files.append(str(target))
        logger.info(f"Saved code to {target} ({len(code)} chars)")

    def _remap_skipped_html_blocks(
        self,
        *,
        task_dir: Path,
        files: List[str],
        skipped_html_blocks: List[tuple[str, str]],
        allowed_html_targets_ordered: List[str],
        allow_root_index_copy: bool,
        output_root: Optional[Path] = None,
    ) -> None:
        if not skipped_html_blocks or not allowed_html_targets_ordered:
            return
        saved_html_names = {
            Path(item).name
            for item in files
            if Path(item).suffix.lower() in (".html", ".htm")
        }
        outstanding_targets = [
            name for name in allowed_html_targets_ordered
            if name not in saved_html_names
        ]
        if not outstanding_targets or len(skipped_html_blocks) != len(outstanding_targets):
            return

        remapped_any = False
        for (original_name, code), target_name in zip(skipped_html_blocks, outstanding_targets):
            if original_name == "index.html" and target_name != "index.html":
                logger.info(
                    "Skipping unsafe remap from skipped index.html block to assigned target %s",
                    target_name,
                )
                continue
            self._save_extracted_code_block(
                task_dir=task_dir,
                rel_path=Path(target_name),
                code=code,
                files=files,
                allow_root_index_copy=allow_root_index_copy,
                allowed_html_targets=set(allowed_html_targets_ordered),
                output_root=output_root,
            )
            logger.info(
                "Remapped skipped HTML block %s -> assigned target %s",
                original_name,
                target_name,
            )
            remapped_any = True
        if remapped_any:
            logger.info("Recovered assigned HTML pages by remapping skipped named blocks")

    def _collect_reference_urls(
        self,
        text: str,
        tool_results: List[Any],
        *,
        agent_type: str = "",
    ) -> List[str]:
        """Collect distinct reference URLs from real browser evidence.

        Builder / polisher output often contains runtime URLs inside generated
        HTML/CSS/JS. Those URLs are not proof that the node actually browsed
        them, so raw text harvesting is limited to research / QA nodes.
        """
        urls: List[str] = []

        def add_url(value: Any) -> None:
            url = str(value or "").strip()
            if not url or not url.lower().startswith(("http://", "https://")):
                return
            cleaned = re.sub(r"[\s\.,;\)\]\}\*_>]+$", "", url)
            parsed = urlparse(cleaned)
            scheme = str(parsed.scheme or "").strip().lower()
            host = str(parsed.hostname or "").strip().lower()
            path = str(parsed.path or "").strip().lower()
            if scheme not in {"http", "https"}:
                return
            if host in {"127.0.0.1", "localhost", "0.0.0.0", "::1"}:
                return
            if path.startswith("/preview") or "/preview/" in path:
                return
            if cleaned not in urls:
                urls.append(cleaned)

        for tr in tool_results or []:
            if not isinstance(tr, dict):
                continue
            data = tr.get("data")
            if isinstance(data, dict):
                for key in ("requested_url", "url", "final_url", "resolved_url"):
                    add_url(data.get(key))
                for key in ("urls", "visited_urls"):
                    raw_urls = data.get(key)
                    if isinstance(raw_urls, list):
                        for item in raw_urls:
                            add_url(item)
            for artifact in tr.get("artifacts") or []:
                if isinstance(artifact, dict):
                    add_url(artifact.get("url"))

        if str(agent_type or "").strip().lower() in {"analyst", "imagegen", "spritesheet", "assetimport", "reviewer", "tester"}:
            for match in _URL_RE.findall(str(text or "")):
                add_url(match)

        return urls

